import { useLocation, useNavigate } from "react-router-dom";
import { useState, useEffect } from "react";
import api from "../../api/axios";

export default function CustomerBookAppointment() {
  const { state } = useLocation();
  const navigate = useNavigate();

  const [vehicleId, setVehicleId] = useState("");
  const [vehicles, setVehicles] = useState([]);

  const [date, setDate] = useState("");
  const [time, setTime] = useState("");
  const [availableSlots, setAvailableSlots] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [minDate, setMinDate] = useState("");

  // Get tomorrow's date as minimum (future dates only)
  useEffect(() => {
    const tomorrow = new Date();
    tomorrow.setDate(tomorrow.getDate() + 1);
    const minDateStr = tomorrow.toISOString().split("T")[0];
    setMinDate(minDateStr);
  }, []);

  // Load available vehicles for dropdown
  useEffect(() => {
    const loadVehicles = async () => {
      try {
        const res = await api.get("/vehicles");
        const available = res.data.filter((v) => v.status === "available");
        setVehicles(available);

        // If coming from vehicle card, auto-select it
        if (state?.vehicleId) {
          setVehicleId(state.vehicleId);
        } else if (available.length > 0) {
          // If coming from navbar, default to first available vehicle
          setVehicleId(available[0]._id);
        }
      } catch (err) {
        alert(err.response?.data?.message || "Failed to load vehicles");
      }
    };

    loadVehicles();
  }, [state]);

  // Load available time slots when date changes
  useEffect(() => {
    const loadTimeSlots = async () => {
      if (!date) {
        setAvailableSlots([]);
        setTime("");
        return;
      }

      setLoading(true);
      setError("");
      setTime("");

      try {
        const res = await api.get(`/customer/appointments/available-slots/${date}`);
        const slots = res.data.slots || [];

        if (slots.length === 0) {
          setError("No available slots on this date. Please select another date.");
          setAvailableSlots([]);
        } else {
          setAvailableSlots(slots);
        }
      } catch (err) {
        const errorMsg = err.response?.data?.message || err.response?.data?.errors?.[0] || "Failed to load available slots";
        setError(errorMsg);
        setAvailableSlots([]);
      } finally {
        setLoading(false);
      }
    };

    loadTimeSlots();
  }, [date]);

  const submit = async (e) => {
    e.preventDefault();

    if (!vehicleId) {
      alert("Please select a vehicle");
      return;
    }

    if (!date) {
      alert("Please select a date");
      return;
    }

    if (!time) {
      alert("Please select a time");
      return;
    }

    try {
      await api.post("/customer/appointments/book", {
        vehicle: vehicleId,
        date,
        time,
      });

      alert("Appointment booked successfully!");
      navigate("/my-appointments");
    } catch (err) {
      const errorMsg = err.response?.data?.message || "Booking failed";
      alert(errorMsg);
    }
  };

  return (
    <div className="page">
      <div className="pageHead">
        <div>
          <div className="pageTitle">Book an Appointment</div>
          <div className="pageSub">Schedule a test drive or viewing (9:00 AM - 5:30 PM, 1-hour slots)</div>
        </div>
      </div>

      <div className="card cardPad" style={{ maxWidth: 560, margin: "32px auto" }}>
        <form onSubmit={submit}>
          <label className="label">Select Vehicle</label>
          <select
            value={vehicleId}
            onChange={(e) => setVehicleId(e.target.value)}
            className="select"
            required
          >
            {vehicles.length === 0 ? (
              <option value="">No available vehicles</option>
            ) : (
              vehicles.map((v) => (
                <option key={v._id} value={v._id}>
                  {v.brand} {v.model || v.type || ""} ({v.year})
                </option>
              ))
            )}
          </select>

          <label className="label" style={{ marginTop: 20 }}>Appointment Date</label>
          <input
            type="date"
            required
            value={date}
            onChange={(e) => setDate(e.target.value)}
            min={minDate}
            className="input"
          />
          <p style={{ fontSize: 12, color: "#666", marginTop: 4 }}>Select a future date (shop closed on holidays)</p>

          {error && (
            <div style={{ 
              marginTop: 12, 
              padding: 12, 
              backgroundColor: "#fee", 
              color: "#c33",
              borderRadius: 4,
              fontSize: 14
            }}>
              {error}
            </div>
          )}

          {date && !error && (
            <>
              <label className="label" style={{ marginTop: 20 }}>Select Time Slot</label>
              {loading ? (
                <div style={{ padding: 12, textAlign: "center", color: "#666" }}>Loading available times...</div>
              ) : availableSlots.length > 0 ? (
                <div style={{ 
                  display: "grid", 
                  gridTemplateColumns: "repeat(auto-fill, minmax(100px, 1fr))",
                  gap: 8,
                  marginTop: 8
                }}>
                  {availableSlots.map((slot) => (
                    <button
                      key={slot.time}
                      type="button"
                      onClick={() => setTime(slot.time)}
                      className="btn"
                      style={{
                        backgroundColor: time === slot.time ? "#007bff" : "#f0f0f0",
                        color: time === slot.time ? "white" : "#333",
                        border: time === slot.time ? "2px solid #0056b3" : "1px solid #ddd",
                        padding: 10,
                        cursor: slot.availableStaffCount > 0 ? "pointer" : "not-allowed",
                        opacity: slot.availableStaffCount > 0 ? 1 : 0.5,
                        fontSize: 14
                      }}
                      disabled={slot.availableStaffCount === 0}
                      title={`${slot.availableStaffCount} staff member${slot.availableStaffCount !== 1 ? 's' : ''} available`}
                    >
                      {slot.time}
                      <br />
                      <small>({slot.availableStaffCount} available)</small>
                    </button>
                  ))}
                </div>
              ) : null}
            </>
          )}

          <div style={{ marginTop: 28, display: "flex", gap: 12 }}>
            <button
              type="submit"
              disabled={vehicles.length === 0 || !date || !time}
              className="btn btnPrimary"
            >
              Book Appointment
            </button>
            <button
              type="button"
              onClick={() => navigate("/")}
              className="btn"
            >
              Cancel
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}
